class Solution {
public:
bool isValidSudoku(vector<vector<int>>& board) {
int n = board.size();
for (int i = 0; i < n; i++) {
  if (board[i].size() != n) return false;
  for (int j = 0; j < n; j++) {
    if (board[i][j] < 1 || board[i][j] > 9) return false;
  }
}
bool checkRow(int r) {
  int num[10] = {0};
  for (int c = 0; c < n; c++) {
    num[board[r][c]]++;
    if (num[board[r][c]] > 1) return false;
  }
  return true;
}
bool checkCol(int c) {
  int num[10] = {0};
  for (int r = 0; r < n; r++) {
    num[board[r][c]]++;
    if (num[board[r][c]] > 1) return false;
  }
  return true;
}
bool checkBox(int r, int c) {
  int num[10] = {0};
  for (int i = 0; i < 3; i++) {
    for (int j = 0; j < 3; j++) {
      num[board[r + i][c + j]]++;
      if (num[board[r + i][c + j]] > 1) return false;
    }
  }
  return true;
}
for (int i = 0; i < n; i++) {
  if (!checkRow(i)) return false;
}
for (int j = 0; j < n; j++) {
  if (!checkCol(j)) return false;
}
for (int i = 0; i < n; i += 3) {
  for (int j = 0; j < n; j += 3) {
    if (!checkBox(i, j)) return false;
  }
}
return true;
};
}

